#!/bin/sh
# build-installer.sh — Build standalone installer.sh from source
# Usage: ./build-installer.sh > installer.sh

set -e
cd "$(dirname "$0")/.."

TEMP_INSTALLER="$(mktemp)"
trap 'rm -f "$TEMP_INSTALLER"' EXIT

# Header with main entry point
cat > "$TEMP_INSTALLER" << 'INSTALLER_HEADER'
#!/bin/sh
# updatebtw standalone installer
# Generated by make — do not edit directly
# Source integrity hash: PLACEHOLDER_HASH

set -e

INSTALLER_URL="https://raw.githubusercontent.com/ChristianWSmith/updatebtw/main/installer.sh"
SOURCES_HASH="PLACEHOLDER_HASH"

_verify_integrity() {
  if ! command -v sha256sum >/dev/null 2>&1; then
    echo "==> updatebtw: sha256sum not found, skipping integrity check" >&2
    return 0
  fi

  local current_hash
  current_hash="$(awk '/^#__END_OF_PAYLOADS__$/{exit} /^SOURCES_HASH=/{next} /^# Source integrity hash:/{next} {print}' "$0" | sha256sum | awk '{print $1}')"

  if [ -n "$current_hash" ] && [ "$current_hash" != "$SOURCES_HASH" ]; then
    echo "==> updatebtw: WARNING — source integrity check failed!" >&2
    echo "    Expected: $SOURCES_HASH" >&2
    echo "    Got:      $current_hash" >&2
    echo "    The installer may have been tampered with." >&2
    return 1
  fi
  return 0
}

if [ "${1:-}" = "--verify" ]; then
  _verify_integrity
  exit $?
fi

if [ ! -t 0 ] && [ "${1:-}" != "--non-interactive" ]; then
  echo "==> updatebtw: piped install is not supported (whiptail TUI needs a terminal)." >&2
  echo "    Download the installer first:" >&2
  echo "      curl -sSfL -o installer.sh $INSTALLER_URL" >&2
  echo "      curl -sSfL -o installer.sh.sha256 $INSTALLER_URL.sha256" >&2
  echo "      sha256sum -c installer.sh.sha256" >&2
  echo "      sudo bash installer.sh" >&2
  exit 1
fi

main() {
  _verify_integrity || {
    echo "==> updatebtw: ABORTING — source integrity check failed." >&2
    echo "    The installer may have been tampered with." >&2
    exit 1
  }

  _check_root

  local _non_interactive=false
  for arg in "$@"; do
    case "$arg" in
      --non-interactive) _non_interactive=true ;;
    esac
  done

  if $_non_interactive; then
    AUR_HELPER="${AUR_HELPER:-yay}"
    AUR_USER="${AUR_USER:-aur_builder}"
    FLATPAK_USER="${FLATPAK_USER:-${SUDO_USER:-$(id -un)}}"
    UPDATE_FREQUENCY="${UPDATE_FREQUENCY:-weekly}"
    UPDATE_TIME="${UPDATE_TIME:-06:00}"
    RUN_AT_BOOT="${RUN_AT_BOOT:-false}"
    ENABLE_REFLECTOR="${ENABLE_REFLECTOR:-true}"
    REFLECTOR_COUNTRY="${REFLECTOR_COUNTRY:-United States}"
    REFLECTOR_INTERVAL="${REFLECTOR_INTERVAL:-30}"
    SILENT_BOOT="${SILENT_BOOT:-false}"

    echo "==> updatebtw: installing with defaults"
    echo "    AUR_HELPER=$AUR_HELPER"
    echo "    AUR_USER=$AUR_USER"
    echo "    FLATPAK_USER=$FLATPAK_USER"
    echo "    UPDATE_FREQUENCY=$UPDATE_FREQUENCY"
    echo "    UPDATE_TIME=$UPDATE_TIME"
    echo "    RUN_AT_BOOT=$RUN_AT_BOOT"
    echo "    ENABLE_REFLECTOR=$ENABLE_REFLECTOR"
    echo "    REFLECTOR_COUNTRY=$REFLECTOR_COUNTRY"
    echo "    REFLECTOR_INTERVAL=$REFLECTOR_INTERVAL"
    echo "    SILENT_BOOT=$SILENT_BOOT"
    echo ""

    local missing=""
    ! command -v whiptail >/dev/null 2>&1 && missing="$missing libnewt"
    ! command -v git >/dev/null 2>&1 && missing="$missing git"
    ! command -v sudo >/dev/null 2>&1 && missing="$missing sudo"
    ! pacman -Qi base-devel >/dev/null 2>&1 && missing="$missing base-devel"
    if [ -n "$missing" ]; then
      echo "Installing missing dependencies:$missing"
      pacman -S --needed --noconfirm $missing >/dev/null 2>&1 || true
    fi
  else
    _check_deps

    whiptail --title "updatebtw" --msgbox \
      "Welcome to updatebtw — the automatic Arch Linux update utility.\n\nNOTE: This project is NOT affiliated with or endorsed by Arch Linux.\nIt is an unofficial third-party tool.\n\nThis installer will configure automatic system updates on your system." \
      12 60

    local freq_choice

    AUR_HELPER=$(whiptail --title "AUR Helper" --radiolist \
      "Select your preferred AUR helper:" 12 65 2 \
      "yay"  "Original Go-based AUR helper (recommended)" ON \
      "paru" "Modern Rust-based AUR helper"             OFF \
       3>&1 1>&2 2>&3) || exit 1

    local detected_user="aur_builder"
    AUR_USER=$(whiptail --title "AUR User" --inputbox \
      "Run AUR helpers (yay/paru) as which user?\n\nThis user will be created if it doesn't already exist.\nWe do NOT recommend using your personal user account." 10 60 "$detected_user" \
      3>&1 1>&2 2>&3) || exit 1

    local detected_flatpak_user="${SUDO_USER:-$(id -un)}"
    FLATPAK_USER=$(whiptail --title "Flatpak User" --inputbox \
      "Run flatpak updates as which user?\n\nThis should be your personal user account,\nsince flatpak installs per-user packages." 10 60 "$detected_flatpak_user" \
      3>&1 1>&2 2>&3) || exit 1

    freq_choice=$(whiptail --title "Update Frequency" --radiolist \
      "How often should updates run?" 14 50 3 \
      "daily"   "Update every day" ON \
      "weekly"  "Update once a week" OFF \
      "monthly" "Update once a month" OFF \
      3>&1 1>&2 2>&3) || exit 1
    UPDATE_FREQUENCY="$freq_choice"

    UPDATE_TIME=$(whiptail --title "Update Time" --inputbox \
      "What time should updates run? (HH:MM, 24-hour format)" 8 60 "06:00" \
      3>&1 1>&2 2>&3) || exit 1

    if whiptail --title "Boot Update" --yesno \
      "Run an update every time the system boots?\n\nThis is useful for systems that are not always on." 10 60; then
      RUN_AT_BOOT="true"
    else
      RUN_AT_BOOT="false"
    fi

    if whiptail --title "Mirrorlist" --yesno \
      "Automatically update mirrorlist via reflector?\n\nThis keeps your package sources fast and up to date." 10 60; then
      ENABLE_REFLECTOR="true"
      REFLECTOR_COUNTRY=$(whiptail --title "Mirror Country" --inputbox \
        "Mirror country (e.g. 'United States', 'Germany'):" 8 60 "United States" \
        3>&1 1>&2 2>&3) || exit 1
      REFLECTOR_INTERVAL=$(whiptail --title "Mirror Update Interval" --inputbox \
        "How often (in days) should the mirrorlist be refreshed?" 8 60 "30" \
        3>&1 1>&2 2>&3) || exit 1
    else
      ENABLE_REFLECTOR="false"
    fi

    local bootloader
    bootloader="$(detect_bootloader)"
    local silent_boot_msg
    case "$bootloader" in
      systemd-boot)
        silent_boot_msg="Configure silent boot?\n\nDetected: systemd-boot\n\nReduces boot messages by modifying boot loader entries,\nmkinitcpio, systemd-fsck services, and kernel printk settings."
        ;;
      grub)
        silent_boot_msg="Configure silent boot?\n\nDetected: GRUB\n\nReduces boot messages by configuring GRUB timeout settings,\nregenerating grub.cfg, and adjusting mkinitcpio, systemd-fsck\nservices, and kernel printk settings."
        ;;
      unknown)
        silent_boot_msg="Configure silent boot?\n\nNo supported bootloader detected (systemd-boot or GRUB).\n\nBootloader-specific changes will be skipped, but generic\nchanges will still apply: mkinitcpio, systemd-fsck services,\nand kernel printk settings."
        ;;
    esac

    if whiptail --title "Silent Boot" --yesno "$silent_boot_msg" 14 65; then
      SILENT_BOOT="true"
    else
      SILENT_BOOT="false"
    fi

    local summary
    summary="AUR Helper: $AUR_HELPER (installed from AUR — verify PKGBUILD manually)\n"
    summary="${summary}Frequency: $UPDATE_FREQUENCY at $UPDATE_TIME\n"
    summary="${summary}Run at boot: $RUN_AT_BOOT\n"
    summary="${summary}Reflector: $ENABLE_REFLECTOR"
    if [ "$ENABLE_REFLECTOR" = "true" ]; then
      summary="${summary} (country: $REFLECTOR_COUNTRY, interval: ${REFLECTOR_INTERVAL:-30}d)\n"
    else
      summary="${summary}\n"
    fi
    summary="${summary}AUR user: $AUR_USER\n"
    summary="${summary}Flatpak user: $FLATPAK_USER\n"
    summary="${summary}Silent boot: $SILENT_BOOT\n"

    if ! whiptail --title "Confirm" --yesno "Apply the following configuration?\n\n${summary}" 16 65; then
      exit 0
    fi
  fi

  echo "Installing AUR helper..."
  _install_aur_helper "$AUR_HELPER" "$AUR_USER" || true
  echo "Configuring AUR user..."
  _setup_aur_user "$AUR_USER" >/dev/null 2>&1 || true
  echo "Writing configuration..."
  write_config
  if [ "$ENABLE_REFLECTOR" = "true" ] && ! command -v reflector >/dev/null 2>&1; then
    echo "Installing reflector..."
    pacman -S --needed --noconfirm reflector >/dev/null 2>&1 || true
  fi
  echo "Installing system files..."
  install_system_files
  echo "Installing systemd units..."
  install_systemd_units
  echo "Enabling timer..."
  enable_timer
  echo "Done."

  if [ "$SILENT_BOOT" = "true" ]; then
    silent_boot
  fi

  if ! $_non_interactive; then
    whiptail --title "Complete" --msgbox \
      "updatebtw has been installed and configured.\n\nUpdates will run automatically on your schedule." \
      8 50
  fi
}

_check_root() {
  if [ "$(id -u)" -ne 0 ]; then
    echo "This installer must be run as root." >&2
    exit 1
  fi
}

_check_deps() {
  local missing=""
  ! command -v whiptail >/dev/null 2>&1 && missing="$missing libnewt"
  ! command -v git >/dev/null 2>&1 && missing="$missing git"
  ! command -v sudo >/dev/null 2>&1 && missing="$missing sudo"
  ! pacman -Qi base-devel >/dev/null 2>&1 && missing="$missing base-devel"

  if [ -z "$missing" ]; then
    return 0
  fi

  if command -v whiptail >/dev/null 2>&1; then
    whiptail --title "Missing Dependencies" --yesno \
      "The following packages are required:\n\n$missing\n\nInstall them now?" \
      12 50 || exit 1
  else
    echo "Missing dependencies:$missing"
    printf "Install now? [Y/n] "
    read -r answer
    case "$answer" in
      n|N|no|NO) exit 1 ;;
    esac
  fi

  # shellcheck disable=SC2086
  pacman -S --needed --noconfirm $missing
}

_install_aur_helper() {
  local helper="$1" user="$2"

  case "$helper" in
    yay|paru) ;;
    *) echo "Invalid AUR helper: $helper" >&2; return 1 ;;
  esac
  if ! printf '%s' "$user" | grep -qE '^[a-z_][a-z0-9_-]*\$?$'; then
    echo "Invalid username: $user" >&2
    return 1
  fi

  command -v "$helper" >/dev/null 2>&1 && return 0

  if [ "$(id -un)" != "$user" ]; then
    if ! id "$user" >/dev/null 2>&1; then
      useradd -m "$user" 2>/dev/null || true
    fi
    mkdir -p /etc/sudoers.d
    # SECURITY (inherent — issue #2: blanket pacman sudo):
    # The AUR user requires unrestricted NOPASSWD access to /usr/bin/pacman.
    # AUR helpers invoke pacman with a wide and evolving set of flags that
    # cannot be exhaustively enumerated or safely restricted. This grants
    # the AUR user the ability to install, remove, query, and modify any
    # packages. Mitigations: log_output for audit trail, dedicated AUR user
    # with no login shell.
    cat > "/etc/sudoers.d/updatebtw-$user-build" << SUDOEOF
Defaults!/usr/bin/pacman log_output
$user ALL=(root) NOPASSWD: /usr/bin/pacman
SUDOEOF
    chmod 440 "/etc/sudoers.d/updatebtw-$user-build"
  fi

  trap 'rm -f "/etc/sudoers.d/updatebtw-$user-build"' EXIT

  local private_tmp
  find /tmp -maxdepth 1 -name "updatebtw-${helper}.*" \( -type d -o -type l \) -exec rm -rf {} + 2>/dev/null || true
  private_tmp="$(mktemp -d "/tmp/updatebtw-$helper.XXXXXX")"
  chmod 700 "$private_tmp"
  chown "$user:$user" "$private_tmp"
  local helper_tmp="$private_tmp/helper"
  mkdir -p "$helper_tmp"
  chown "$user:$user" "$helper_tmp"
  trap 'rm -f "/etc/sudoers.d/updatebtw-$user-build"; rm -rf "$private_tmp"' EXIT

  local build_script
  build_script="$private_tmp/build.sh"
  # SECURITY (inherent — issue #1: untrusted PKGBUILD execution):
  # makepkg executes the build() and package() functions from the PKGBUILD,
  # which is downloaded from the AUR and runs as arbitrary shell code. A
  # malicious or compromised PKGBUILD can execute any command during the
  # build process, including installing trojaned packages via the scoped
  # sudoers rule above. This is the fundamental trust model of the AUR —
  # no tool that auto-builds from the AUR can eliminate this risk.
  #
  # Mitigations: PKGBUILD review prompt (defaults to [Y/n]), PKGBUILD
  # SHA256 printed after build for manual verification, build runs as
  # unprivileged AUR user (not root).
  cat > "$build_script" << BUILDEOF
#!/bin/sh
set -e
HELPER="\$1"
HELPER_TMP="\$2"
# SECURITY (inherent — issue #6: supply chain trust):
# The AUR helper is cloned over HTTPS from aur.archlinux.org. This trusts
# the AUR infrastructure, its maintainers, and the TLS certificate chain.
# A compromise of any AUR maintainer account, the AUR build servers, or a
# TLS MITM attack could result in a malicious PKGBUILD being cloned and
# built. The software has no mechanism for independent PKGBUILD verification
# beyond the SHA256 printed after build for manual comparison.
git clone --depth=1 "https://aur.archlinux.org/\$HELPER.git" "\$HELPER_TMP"
cd "\$HELPER_TMP"

# Install build dependencies as root before running makepkg
# makepkg -makedepends requires sudo, which the aur user may not have
# SECURITY (inherent — issue #11: auto dependency install):
# The dependency list is parsed from the PKGBUILD via makepkg --printsrcinfo.
# A malicious PKGBUILD could list unexpected dependencies, causing arbitrary
# packages to be installed as root via sudo pacman -S. This is inherent to
# the AUR build process — makepkg requires build dependencies to be installed
# before it can run, and the dependency list comes from the untrusted PKGBUILD.
# Mitigation: sudo is scoped to /usr/bin/pacman only (see issue #2).
_deps="\$(makepkg --printsrcinfo 2>/dev/null | sed -n 's/^\tmakedepends = //p' | tr '\n' ' ')"
if [ -n "\$_deps" ]; then
  sudo pacman -S --needed --noconfirm \$_deps 2>/dev/null || true
fi

makepkg --noconfirm
BUILDEOF
  chmod 755 "$build_script"
  trap 'rm -f "/etc/sudoers.d/updatebtw-$user-build" "$build_script"; rm -rf "$private_tmp"' EXIT

  # PKGBUILD review prompt before building (H3)
  if [ -t 0 ] && [ "${UPDATEBTW_AUTO_INSTALL_AUR:-}" != "1" ]; then
    echo "==> AUR helper '$helper' will be built from the AUR."
    echo "    Review the PKGBUILD before proceeding:"
    echo "    https://aur.archlinux.org/cgit/aur.git/tree/PKGBUILD?h=$helper"
    printf "    Continue? [Y/n] "
    read -r _aur_answer
    case "$_aur_answer" in
      n|N) echo "Aborted."; return 1 ;;
    esac
  fi

  if [ "$(id -un)" = "$user" ]; then
    sh "$build_script" "$helper" "$helper_tmp"
  else
    su - "$user" -s /bin/sh -- "$build_script" "$helper" "$helper_tmp"
  fi

  if [ -f "$helper_tmp/PKGBUILD" ]; then
    local pkgbuild_hash
    pkgbuild_hash="$(sha256sum "$helper_tmp/PKGBUILD" | awk '{print $1}')"
    echo "PKGBUILD SHA256: $pkgbuild_hash"
    echo "Verify at: https://aur.archlinux.org/cgit/aur.git/tree/PKGBUILD?h=$helper"
  fi

  sudo pacman -U --noconfirm "$helper_tmp"/*.pkg.tar.* && printf "Installed %s\n" "$helper" || printf "Warning: failed to install %s\n" "$helper"

  rm -f "$build_script"
  command -v "$helper" >/dev/null 2>&1
}

_setup_aur_user() {
  local user="$1"
  [ -n "$user" ] || return 1

  if ! id "$user" >/dev/null 2>&1; then
    useradd -m "$user" 2>/dev/null || true
  fi

  rm -f "/etc/sudoers.d/updatebtw-$user-build" 2>/dev/null || true
  rm -f "/etc/sudoers.d/updatebtw-$user" 2>/dev/null || true
  mkdir -p /etc/sudoers.d
  # SECURITY (inherent — issue #2: blanket pacman sudo):
  # See comment in _install_aur_helper() for full rationale. The AUR user
  # needs unrestricted access to /usr/bin/pacman. The -U path restriction
  # and subcommand-scoped rules are dropped because AUR helpers use a wide
  # and evolving set of pacman flags that cannot be safely enumerated.
  cat > "/etc/sudoers.d/updatebtw-$user" << SUDOEOF
Defaults!/usr/bin/pacman log_output
$user ALL=(root) NOPASSWD: /usr/bin/pacman
SUDOEOF
  chmod 440 "/etc/sudoers.d/updatebtw-$user"
}
INSTALLER_HEADER

# Embed config module
echo "" >> "$TEMP_INSTALLER"
echo "# === config module ===" >> "$TEMP_INSTALLER"
cat src/lib/config.sh >> "$TEMP_INSTALLER"

# Embed backup module
echo "" >> "$TEMP_INSTALLER"
echo "# === backup module ===" >> "$TEMP_INSTALLER"
cat src/lib/backup.sh >> "$TEMP_INSTALLER"

# Embed silent-boot module
echo "" >> "$TEMP_INSTALLER"
echo "# === silent-boot module ===" >> "$TEMP_INSTALLER"
cat src/lib/silent-boot.sh >> "$TEMP_INSTALLER"

# Embed updater module
echo "" >> "$TEMP_INSTALLER"
echo "# === updater module ===" >> "$TEMP_INSTALLER"
cat src/lib/updater.sh >> "$TEMP_INSTALLER"

# Generate install_file_* functions with base64-encoded payloads for each file
embed_payload() {
  local src="$1"
  local dest="$2"
  local mode="$3"
  local func_name

  local clean_dest
  clean_dest="$(printf '%s' "$dest" | sed 's|^/||')"
  func_name="install_$(printf '%s' "$clean_dest" | tr '/' '_' | tr '.' '_' | tr '-' '_')"

  echo "" >> "$TEMP_INSTALLER"
  echo "# payload: $src -> $dest" >> "$TEMP_INSTALLER"
  echo "${func_name}() {" >> "$TEMP_INSTALLER"
  echo "  local dest=\"$dest\"" >> "$TEMP_INSTALLER"
  echo "  mkdir -p \"\$(dirname \"\$dest\")\"" >> "$TEMP_INSTALLER"
  printf '%s\n' "$(base64 -w0 "$src" | sed 's/^/  echo "/; s/$/" | base64 -d > "$dest"/')" >> "$TEMP_INSTALLER"
  printf '  chmod %s "$dest"\n' "$mode" >> "$TEMP_INSTALLER"
  echo "}" >> "$TEMP_INSTALLER"
}

embed_payload src/updatebtw /usr/bin/updatebtw 755
embed_payload src/lib/config.sh /usr/lib/updatebtw/config.sh 644
embed_payload src/lib/backup.sh /usr/lib/updatebtw/backup.sh 644
embed_payload src/lib/updater.sh /usr/lib/updatebtw/updater.sh 644
embed_payload src/lib/silent-boot.sh /usr/lib/updatebtw/silent-boot.sh 644
embed_payload src/lib/installer.sh /usr/lib/updatebtw/installer.sh 644
embed_payload systemd/updatebtw-update.service /etc/systemd/system/updatebtw-update.service 644
embed_payload systemd/updatebtw-update.timer /etc/systemd/system/updatebtw-update.timer 644
embed_payload systemd/updatebtw-boot.service /etc/systemd/system/updatebtw-boot.service 644
embed_payload config/updatebtw.conf /etc/updatebtw/updatebtw.conf 600

# Generate install_system_files() and install_systemd_units()
echo "" >> "$TEMP_INSTALLER"
echo "install_system_files() {" >> "$TEMP_INSTALLER"
echo "  install_usr_bin_updatebtw" >> "$TEMP_INSTALLER"
echo "  install_usr_lib_updatebtw_config_sh" >> "$TEMP_INSTALLER"
echo "  install_usr_lib_updatebtw_backup_sh" >> "$TEMP_INSTALLER"
echo "  install_usr_lib_updatebtw_updater_sh" >> "$TEMP_INSTALLER"
echo "  install_usr_lib_updatebtw_silent_boot_sh" >> "$TEMP_INSTALLER"
echo "  install_usr_lib_updatebtw_installer_sh" >> "$TEMP_INSTALLER"
echo "}" >> "$TEMP_INSTALLER"
echo "" >> "$TEMP_INSTALLER"
echo "install_systemd_units() {" >> "$TEMP_INSTALLER"
echo "  install_etc_systemd_system_updatebtw_update_service" >> "$TEMP_INSTALLER"
echo "  install_etc_systemd_system_updatebtw_update_timer" >> "$TEMP_INSTALLER"
echo "  install_etc_systemd_system_updatebtw_boot_service" >> "$TEMP_INSTALLER"
echo "}" >> "$TEMP_INSTALLER"
echo "" >> "$TEMP_INSTALLER"
echo "enable_timer() {" >> "$TEMP_INSTALLER"
echo "  systemctl daemon-reload 2>/dev/null || true" >> "$TEMP_INSTALLER"
echo "" >> "$TEMP_INSTALLER"
echo "  # Generate timer drop-in from configured schedule" >> "$TEMP_INSTALLER"
echo "  local dropin_dir=\"/etc/systemd/system/updatebtw-update.timer.d\"" >> "$TEMP_INSTALLER"
echo "  mkdir -p \"\$dropin_dir\"" >> "$TEMP_INSTALLER"
echo "  local calendar" >> "$TEMP_INSTALLER"
echo "  calendar=\"\$(calendar_from_config)\"" >> "$TEMP_INSTALLER"
echo "  printf '[Timer]\nOnCalendar=%s\n' \"\$calendar\" > \"\$dropin_dir/schedule.conf\"" >> "$TEMP_INSTALLER"
echo "  chmod 644 \"\$dropin_dir/schedule.conf\"" >> "$TEMP_INSTALLER"
echo "" >> "$TEMP_INSTALLER"
echo "  systemctl daemon-reload 2>/dev/null || true" >> "$TEMP_INSTALLER"
echo "  systemctl enable --now updatebtw-update.timer 2>/dev/null || true" >> "$TEMP_INSTALLER"
echo '  if [ "$RUN_AT_BOOT" = "true" ]; then' >> "$TEMP_INSTALLER"
echo "    systemctl enable updatebtw-boot.service 2>/dev/null || true" >> "$TEMP_INSTALLER"
echo "  fi" >> "$TEMP_INSTALLER"
echo "}" >> "$TEMP_INSTALLER"
echo "" >> "$TEMP_INSTALLER"
echo "main \"\$@\"" >> "$TEMP_INSTALLER"
echo "#__END_OF_PAYLOADS__" >> "$TEMP_INSTALLER"

# Compute hash of everything before the end-of-payloads delimiter,
# excluding the SOURCES_HASH variable and the integrity hash comment line.
# This ensures the hash value itself is not part of the hash computation.
#
# SECURITY (inherent — issue #7: self-referential integrity hash):
# This SHA256 hash proves the installer was not modified after build, but
# cannot prove the file came from the legitimate build process (provenance).
# An attacker who replaces the entire installer.sh (e.g., MITM on the GitHub
# raw content URL) would have a file where the embedded hash matches the
# file's content. Without external signature verification (GPG, cosign, etc.),
# provenance cannot be established. This is inherent to self-signed integrity
# checks. Mitigations: HTTPS for download, separate .sha256 file.
SOURCES_HASH="$(awk '/^#__END_OF_PAYLOADS__$/{exit} /^SOURCES_HASH=/{next} /^# Source integrity hash:/{next} {print}' "$TEMP_INSTALLER" | sha256sum | awk '{print $1}')"

# Replace placeholder hash with actual hash
sed -i "s/PLACEHOLDER_HASH/$SOURCES_HASH/g" "$TEMP_INSTALLER"

cat "$TEMP_INSTALLER"
